#include<bits/stdc++.h>
using namespace std;
long long n,k,a[105][105];
void init(){
    a[0][0]=1;
    for(int i=1;i<=100;i++){
        for(int j=0;j<=i;j++){
            a[i][j]=a[i-1][j]+a[i-1][j-1];
        }
    }
}
int main(){
    cin>>n>>k;
    init();
    long long ans=0,cnt=0;
    for(int i=62;i>=0;i--){;
               //            cout<<i<<" "<<int(n&(1<<i))<<"\n";
        if(n&(1ll<<i)){
          if(k-cnt>=0) ans+=a[i][k-cnt];
            cnt++;
        }
    }
    if(cnt==k) ans++;
    cout<<ans;
    return 0;
}
